const hora = new Date().getHours();
const diaSemana = new Date().getDay();
const isHorarioComercial = (hora >= 8 && hora <= 18);
const isFimDeSemana = (diaSemana === 0 || diaSemana === 6);

if (!isHorarioComercial) palavrasEncontradas.push('fora-horario');
if (isFimDeSemana) palavrasEncontradas.push('fim-de-semana');

// ============================================
// CRÍTICA (4)
// ============================================
const palavrasCriticas = [
  'sem energia', 'falta energia', 'energia caiu', 'luz apagou', 'no-break', 'nobreak', 'gerador falhou', 'queda de energia',
  'sem internet', 'internet caiu', 'rede caiu', 'wifi fora', 'conexão falhou', 'sem conectividade', 'link caiu', 'fibra caiu',
  'servidor caiu', 'servidor fora', 'servidor parado', 'data center', 'servidor não responde', 'instância caiu',
  'sistema fora', 'sistema parado', 'sistema caiu', 'fora do ar', 'tudo parado', 'não funciona nada', 'app fora', 'site fora', 'portal fora',
  'produção parada', 'fábrica parada', 'linha parada', 'operação parada', 'sem operar', 'operação crítica',
  'emergência', 'crítico', 'urgentíssimo', 'desesperador', 'catástrofe', 'colapso', 'inacessível', 'totalmente bloqueado',
  'invasão', 'hackeado', 'hacker', 'ataque', 'ransomware', 'vírus', 'malware', 'phishing confirmado',
  'vazamento de dados', 'brecha de segurança', 'acesso indevido confirmado', 'dados expostos',
  'dados perdidos', 'backup falhou', 'arquivo corrompido', 'banco de dados corrompido', 'perda de dados',
  'disco queimou', 'fonte queimou', 'equipamento queimou', 'hardware falhou',
  'incêndio', 'enchente', 'alagamento', 'curto-circuito', 'explosão', 'desastre',
  'fraude confirmada', 'desvio de valores', 'conta bloqueada', 'bloqueio judicial', 'penhora',
  'liminar', 'ordem judicial', 'prazo judicial', 'intimação', 'execução fiscal',
];

for (const palavra of palavrasCriticas) {
  if (textoCompleto.includes(palavra)) {
    prioridade_id = 4;
    motivo = "CRÍTICA: Sistema inoperante ou emergência detectada";
    palavrasEncontradas.push(palavra);
    break;
  }
}

// ============================================
// ALTA (3) — só se não for crítica
// ============================================
if (prioridade_id < 4) {
  const palavrasAlta = [
    'urgente', 'asap', 'rápido', 'quanto antes', 'imediatamente', 'com urgência', 'o mais rápido', 'preciso hoje',
    'não consigo trabalhar', 'improdutivo', 'parado parcialmente', 'bloqueado', 'impedido', 'travado no trabalho',
    'atrasado', 'prazo', 'deadline', 'vencimento', 'vence hoje', 'vence amanhã', 'prejuízo', 'multa', 'juros', 'penalidade',
    'contrato em risco', 'cliente vai cancelar', 'perda de contrato',
    'cliente insatisfeito', 'cliente reclamando', 'reclamação', 'nervoso', 'irritado', 'cliente esperando',
    'escalado', 'escalonado', 'diretoria pediu', 'gestor pediu', 'ceo pediu',
    'bug', 'erro', 'falha', 'tela azul', 'crash', 'travou', 'congelou', 'loop infinito',
    'lentidão', 'demora', 'não carrega', 'não abre', 'não salva', 'não envia', 'não processa',
    'não consigo logar', 'login falhou', 'senha não funciona', 'bloqueado no sistema', 'sem acesso ao sistema',
    'usuário bloqueado', 'autenticação falhou', 'token expirou',
    'pagamento não processado', 'boleto não gerou', 'transação falhou', 'cobrança errada', 'valor incorreto',
    'nota fiscal errada', 'fatura incorreta', 'estorno urgente',
    'folha atrasada', 'pagamento de salário', 'rescisão urgente', 'afastamento',
    'entrega atrasada', 'fornecedor cancelou', 'estoque zerado', 'ruptura de estoque',
  ];

  for (const palavra of palavrasAlta) {
    if (textoCompleto.includes(palavra)) {
      prioridade_id = 3;
      motivo = "ALTA: Urgência ou impacto significativo";
      palavrasEncontradas.push(palavra);
      break;
    }
  }
}

// ============================================
// MÉDIA (2) — só se ainda for baixa
// ============================================
if (prioridade_id < 3) {
  const palavrasMedia = [
    // Problemas reais mas sem urgência imediata
    'intermitente', 'às vezes', 'ocasional', 'esporádico', 'de vez em quando', 'nem sempre',
    'instável', 'oscilando', 'oscilação', 'funcionando parcialmente', 'lento mas funciona',
    // Erros visuais / comportamento estranho
    'layout quebrado', 'exibe errado', 'mensagem estranha', 'comportamento estranho', 'exibindo incorreto',
    'campo errado', 'campo faltando', 'tela errada', 'dado errado', 'valor divergente',
    'relatório incorreto', 'relatório errado', 'número errado', 'cálculo errado',
    // Impacto parcial
    'alguns usuários', 'parte dos usuários', 'afetando parte', 'impactando alguns',
    'só eu', 'apenas eu', 'somente eu', 'só no meu', 'apenas no meu',
    // Solicitações com algum impacto
    'preciso de acesso', 'preciso de permissão', 'sem permissão', 'permissão negada',
    'não tenho acesso', 'acesso negado', 'não consigo visualizar', 'não consigo abrir',
    // Integrações / importações
    'integração falhou', 'importação falhou', 'exportação falhou', 'sincronização falhou',
    'arquivo não importou', 'planilha com erro', 'dados não sincronizaram',
    // Configuração / ajuste
    'configuração errada', 'configurar', 'ajustar', 'alterar configuração', 'parâmetro errado',
  ];

  for (const palavra of palavrasMedia) {
    if (textoCompleto.includes(palavra)) {
      prioridade_id = 2;
      motivo = "MÉDIA: Problema real sem urgência crítica";
      palavrasEncontradas.push(palavra);
      break;
    }
  }
}

// ============================================
// REGRAS ESPECIAIS — elevação por contexto
// ============================================

// Assunto financeiro sobe para Alta se ainda for Baixa/Média
const palavrasFinanceiro = [
  'pagamento', 'boleto', 'fatura', 'nota fiscal', 'reembolso',
  'cobrança', 'transferência', 'pix', 'ted', 'doc', 'débito', 'crédito'
];
for (const palavra of palavrasFinanceiro) {
  if (textoCompleto.includes(palavra) && prioridade_id < 3) {
    prioridade_id = 3;
    motivo += " + Assunto financeiro";
    palavrasEncontradas.push(palavra + '(financeiro)');
    break;
  }
}

// Fora do horário comercial sobe 1 nível (máximo Crítica)
if (!isHorarioComercial && prioridade_id < 4) {
  prioridade_id = Math.min(prioridade_id + 1, 4);
  motivo += " + Fora do horário comercial";
}

// Fim de semana sobe 1 nível (máximo Crítica)
if (isFimDeSemana && prioridade_id < 4) {
  prioridade_id = Math.min(prioridade_id + 1, 4);
  motivo += " + Fim de semana";
}

// ============================================
// LOG
// ============================================
console.log('='.repeat(50));
console.log('CLASSIFICAÇÃO DE PRIORIDADE:');
console.log(`Horário comercial: ${isHorarioComercial ? 'Sim' : 'Não'} (${hora}h)`);
console.log(`Fim de semana: ${isFimDeSemana ? 'Sim' : 'Não'}`);
console.log(`Prioridade: ${prioridade_id}`);
console.log(`Motivo: ${motivo}`);
console.log(`Palavras: ${palavrasEncontradas.join(', ')}`);
console.log('='.repeat(50));

// ============================================
// SAÍDA
// ============================================
const inputData = $input.first().json;
const clienteId = inputData.clienteId || null;
const departamento_id = inputData.departamento_id || 7;

console.log(`🔴 CLASSIFICAR - departamento_id recebido: ${inputData.departamento_id}`);
console.log(`🔴 CLASSIFICAR - departamento_id final: ${departamento_id}`);

return {
  clienteId,
  prioridade_id,
  prioridade_motivo: motivo,
  palavras_chave: palavrasEncontradas,
  assunto: dadosCliente.assunto,
  mensagem_original: dadosCliente.mensagem,
  canal: dadosCliente.canal,
  dadosCliente: dadosCliente.cliente,
  metadata_horario: { hora, horario_comercial: isHorarioComercial, fim_de_semana: isFimDeSemana },
  departamento_id
};

const data = $input.first().json;

// No ramo TRUE, o cliente acabou de ser criado
const clienteId = data[0]?.id || data.id;

// 🔥 DEPARTAMENTO_ID VEM DO Decidir se Cria Cliente (via Criar Cliente) 🔥
const departamento_id = data.departamento_id;

console.log('Ramo TRUE - Cliente ID:', clienteId);
console.log('Ramo TRUE - departamento_id:', departamento_id);

return {
  clienteId: clienteId,
  dadosCliente: {
    nome: data.nome,
    email: data.email,
    telefone: data.telefone
  },
  departamento_id: departamento_id
