const data = $input.first().json;

// 🔥 DEPARTAMENTO_ID VEM DO Decidir se Cria Cliente 🔥
const departamento_id = data.departamento_id;

console.log('Ramo FALSE - clienteId:', data.clienteId);
console.log('Ramo FALSE - departamento_id:', departamento_id);

let clienteId = data.clienteId;

return {
  clienteId: clienteId,
  dadosCliente: data.dadosCliente,
  departamento_id: departamento_id
};

const inputData = $input.first().json;

console.log('=' .repeat(50));
console.log('FORÇAR CLIENTE ID - DADOS RECEBIDOS:');
console.log(JSON.stringify(inputData, null, 2));
console.log('=' .repeat(50));

let clienteId = inputData.clienteId;

if (!clienteId && inputData.dadosCliente && inputData.dadosCliente.id) {
  clienteId = inputData.dadosCliente.id;
}

console.log('Cliente ID final:', clienteId);
console.log('Departamento ID recebido:', inputData.departamento_id);

if (!clienteId) {
  throw new Error('clienteId não encontrado. Dados: ' + JSON.stringify(inputData));
}

// 🔥 CORRIGIDO: Mapear canal para ID (apenas uma declaração)
const canalMap = {
  'whatsapp': 1,
  'email': 2,
  'teams': 3,
  'microsoft teams': 3,
  'formulario web': 4,
  'formulário web': 4,
  'formulario': 4,
  'formulário': 4,
  'portal do cliente': 5,
  'portal': 5,
  'desconhecido': 1
};

// Pega o canal do inputData
let canalNome = (inputData.canal || 'whatsapp').toLowerCase().trim();
// Remove acentos para mapeamento
canalNome = canalNome.normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const canalId = canalMap[canalNome] || 1;

console.log(`📞 Canal identificado: "${inputData.canal}" → ID: ${canalId}`);

// Usar o departamento_id que veio do Mapear setor
const departamento_id = inputData.departamento_id || 7;

console.log(`✅ Departamento ID final: ${departamento_id}`);

return {
  cliente_id: clienteId,
  canal_id: canalId,
  assunto: inputData.assunto,
  mensagem_original: inputData.mensagem_original,
  prioridade_id: inputData.prioridade_id || 2,
  status: "Novo",
  departamento_id: departamento_id
};

// Nó "Mapear setor" - Versão CORRIGIDA com suporte a ID direto e melhor debug
const inputData = $input.first().json;

console.log('=' .repeat(50));
console.log('🏷️ MAPEAMENTO DE SETOR');
console.log('=' .repeat(50));

// 🔥 NOVO: Se já veio como número (ID do departamento), usa direto
if (inputData.departamento_id && typeof inputData.departamento_id === 'number' && inputData.departamento_id >= 1 && inputData.departamento_id <= 7) {
  const deptoMapIdToName = {
    1: 'Financeiro', 2: 'RH', 3: 'TI', 4: 'Suprimentos',
    5: 'Administrativo', 6: 'Jurídico', 7: 'Geral'
  };
  const nomeSetor = deptoMapIdToName[inputData.departamento_id];
  console.log(`✅ Já veio com departamento_id: ${inputData.departamento_id} → ${nomeSetor}`);

  return {
    ...inputData,
    departamento_id: inputData.departamento_id,
    nome_setor_original: nomeSetor,
    setor_normalizado: nomeSetor.toLowerCase(),
    mapeado_em: new Date().toISOString(),
    veio_como_id: true
  };
}

// Pega o setor de diferentes lugares possíveis
let setor = inputData.extraido?.setor || 
           inputData.setor || 
           inputData.extraido?.cliente?.departamento || 
           inputData.departamento ||
           'Geral';

console.log('Setor ORIGINAL:', JSON.stringify(setor));
console.log('Origem do chamado:', inputData.extraido?.origem || inputData.origem || 'desconhecido');
console.log('Tipo:', typeof setor);

// Garantir que setor é string
if (!setor || typeof setor !== 'string') {
  setor = 'Geral';
  console.log('⚠️ Setor inválido, usando padrão: Geral');
}

// Converter para minúsculo e limpar
const setorLower = setor.toLowerCase().trim();
console.log(`Setor normalizado: "${setorLower}"`);

// Mapeamento direto
let departamento_id = null;

if (setorLower === 'financeiro' || setorLower === 'finanças' || setorLower === 'financas') {
  departamento_id = 1;
  console.log('🎯 Financeiro → ID 1');
}
else if (setorLower === 'rh' || setorLower === 'recursos humanos' || setorLower === 'hr') {
  departamento_id = 2;
  console.log('🎯 RH → ID 2');
}
else if (setorLower === 'ti' || setorLower === 'tecnologia' || setorLower === 'informática' || setorLower === 'informatica' || setorLower === 'it') {
  departamento_id = 3;
  console.log('🎯 TI → ID 3');
}
else if (setorLower === 'suprimentos' || setorLower === 'suprimentos' || setorLower === 'compras' || setorLower === 'logística' || setorLower === 'logistica' || setorLower === 'supply') {
  departamento_id = 4;
  console.log('🎯 Suprimentos → ID 4');
}
else if (setorLower === 'administrativo' || setorLower === 'adm' || setorLower === 'admin' || setorLower === 'administracao') {
  departamento_id = 5;
  console.log('🎯 Administrativo → ID 5');
}
else if (setorLower === 'jurídico' || setorLower === 'juridico' || setorLower === 'legal') {
  departamento_id = 6;
  console.log('🎯 Jurídico → ID 6');
}
else if (setorLower === 'geral' || setorLower === 'general' || setorLower === '') {
  departamento_id = 7;
  console.log('🎯 Geral → ID 7');
}
else {
  // Busca parcial para palavras próximas
  if (setorLower.includes('suprimento') || setorLower.includes('compras') || setorLower.includes('logist')) {
    departamento_id = 4;
    console.log('🎯 Suprimentos (parcial) → ID 4');
  }
  else if (setorLower.includes('finance') || setorLower.includes('financ')) {
    departamento_id = 1;
    console.log('🎯 Financeiro (parcial) → ID 1');
  }
  else if (setorLower.includes('tecno') || setorLower.includes('inform')) {
    departamento_id = 3;
    console.log('🎯 TI (parcial) → ID 3');
  }
  else if (setorLower.includes('admin')) {
    departamento_id = 5;
    console.log('🎯 Administrativo (parcial) → ID 5');
  }
  else if (setorLower.includes('jurid')) {
    departamento_id = 6;
    console.log('🎯 Jurídico (parcial) → ID 6');
  }
  else if (setorLower.includes('rh') || setorLower.includes('recurs')) {
    departamento_id = 2;
    console.log('🎯 RH (parcial) → ID 2');
  }
  else {
    departamento_id = 7;
    console.log(`⚠️ Setor "${setor}" não reconhecido, usando Geral (ID 7)`);
  }
}

console.log('=' .repeat(50));
console.log(`✅ RESULTADO: "${setor}" → departamento_id: ${departamento_id}`);
console.log('=' .repeat(50));

// Retornar os dados atualizados
return {
  ...inputData,
  departamento_id: departamento_id,
  nome_setor_original: setor,
  setor_normalizado: setorLower,
  mapeado_em: new Date().toISOString(),
  veio_como_id: false
};

const authResp = $input.first().json;
const dadosCliente = $('Decidir se Cria Cliente').first().json;

// Supabase signUp retorna { id, email, ... } em caso de sucesso
// ou { msg: 'User already registered' } se já existe
