} else if (authClienteId) {
  console.log('✅ Auth criado para cliente:', authClienteId);
} else {
  console.log('⚠️ Auth: resposta inesperada:', JSON.stringify(authResp));
}

return {
  ...dadosCliente,
  auth_cliente_id: authClienteId
};
